#include <stdio.h>
#include <stdbool.h>
#define MAX_N 1000

void dfs(int node, bool visited[], int adj[][MAX_N], int n) {
    visited[node] = true;
    printf("%d ", node + 1);
    for (int i = 0; i < n; ++i) {
        if (adj[node][i] && !visited[i]) {
            dfs(i, visited, adj, n);
        }
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int adj[MAX_N][MAX_N] = {0};
        for (int i = 0; i < m; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            adj[u-1][v-1] = adj[v-1][u-1] = 1;
        }
        bool visited[MAX_N] = {false};
        dfs(0, visited, adj, n);
        printf("\n");
    }
    return 0;
}

