const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = parseInt(data[idx++], 10);
let output = [];
for (let t = 0; t < T; ++t) {
  const n = parseInt(data[idx++], 10);
  const m = parseInt(data[idx++], 10);
  const adj = Array.from({ length: n }, () => []);
  for (let i = 0; i < m; ++i) {
    const u = parseInt(data[idx++], 10) - 1;
    const v = parseInt(data[idx++], 10) - 1;
    adj[u].push(v);
    adj[v].push(u);
  }
  for (let i = 0; i < n; ++i) adj[i].sort((a, b) => a - b);
  const visited = Array(n).fill(false);
  const order = [];
  function dfs(u) {
    visited[u] = true;
    order.push(u + 1);
    for (const v of adj[u]) {
      if (!visited[v]) dfs(v);
    }
  }
  dfs(0);
  output.push(order.join(' '));
}
